import React from 'react';
function FORMA(props) {
    return (
        <div className="mb-3 col-12 col-md-6">
            <div className="font-weight-bolder text-uppercase">{props.title}.</div>
            <div>{props.local}</div>
    <div className="text-muted">{props.sem ? props.sem+"º Semestre | " : ""}{props.concluido ? "Concluído" : "Conclusão"} em {props.data}</div>
        </div>
    );
}

export default FORMA;
