import React from 'react';
function EXP(props) {
    return (
        <div className="mb-3 col-12 col-md-6">
            <span className="font-weight-bolder text-uppercase">{props.title}. </span><p className="small text-muted mb-1">{props.data} </p>
            <span>{props.children}</span>
        </div>
    );
}

export default EXP;
