import React from 'react';
function ATIV(props) {
    return (
        <div className="mb-3 col-12 col-md-6">
            <div className="font-weight-bolder text-uppercase">{props.title}.</div>
            <div className="text-muted small">({props.local}, conclusão em {props.data}).</div>
        </div>
    );
}

export default ATIV;
